begin;
create or replace function public.is_active_user() returns boolean language sql stable security definer set search_path=pg_catalog,public as $$select exists(select 1 from public.profiles where id=auth.uid() and status='active')$$;
create or replace function public.is_platform_admin() returns boolean language sql stable security definer set search_path=pg_catalog,public as $$select exists(select 1 from public.profiles where id=auth.uid() and status='active' and platform_role='platform_admin')$$;
create or replace function public.is_model_member(p_model_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$select exists(select 1 from public.model_members where model_id=p_model_id and user_id=auth.uid() and status='active')$$;
create or replace function public.is_agency_admin(p_agency_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$select exists(select 1 from public.agency_members where agency_id=p_agency_id and user_id=auth.uid() and role='administrator' and status='active')$$;
create or replace function public.is_assigned_agency_manager(p_model_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$select exists(select 1 from public.model_access_assignments a join public.agency_members m on m.agency_id=a.agency_id and m.user_id=a.manager_user_id and m.role='manager' and m.status='active' join public.models x on x.id=a.model_id and x.agency_id=a.agency_id where a.model_id=p_model_id and a.manager_user_id=auth.uid())$$;
create or replace function public.can_view_model(p_model_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$select public.is_active_user() and (public.is_platform_admin() or public.is_model_member(p_model_id) or public.is_assigned_agency_manager(p_model_id) or exists(select 1 from public.models m where m.id=p_model_id and public.is_agency_admin(m.agency_id)))$$;
create or replace function public.can_manage_model(p_model_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$select public.is_platform_admin() or exists(select 1 from public.models m where m.id=p_model_id and public.is_agency_admin(m.agency_id))$$;
revoke all on function public.is_active_user() from public; revoke all on function public.is_platform_admin() from public; revoke all on function public.is_model_member(uuid) from public; revoke all on function public.is_agency_admin(uuid) from public; revoke all on function public.is_assigned_agency_manager(uuid) from public; revoke all on function public.can_view_model(uuid) from public; revoke all on function public.can_manage_model(uuid) from public;
grant execute on function public.is_active_user(),public.is_platform_admin(),public.is_model_member(uuid),public.is_agency_admin(uuid),public.is_assigned_agency_manager(uuid),public.can_view_model(uuid),public.can_manage_model(uuid) to authenticated;
commit;
